content:
{
  "sentences": [
    {
      "text": "你為什麼不想吃牛肉麵？",
      "pinyin": "Nǐ wèishénme bù xiǎng chī niúròumiàn?",
      "pinyin_numeric": "ni3 wei4 shen2 me0 bu4 xiang3 chi1 niu2 rou4 mian4",
      "translation_en": "Why don't you want to eat beef noodles?",
      "translation_ko": "왜 소고기 국수를 먹고 싶지 않으세요?"
    },
    {
      "text": "因為我肚子餓，所以想吃飯。",
      "pinyin": "Yīnwèi wǒ dùzi è, suǒyǐ xiǎng chī fàn.",
      "pinyin_numeric": "yin1 wei4 wo3 du4 zi0 e4, suo3 yi3 xiang3 chi1 fan4",
      "translation_en": "Because I'm hungry, so I want to eat rice.",
      "translation_ko": "배가 고파서 밥을 먹고 싶어요."
    },
    {
      "text": "他為什麼不想喝咖啡？因為他口渴，想喝水。",
      "pinyin": "Tā wèishénme bù xiǎng hē kāfēi? Yīnwèi tā kǒukě, xiǎng hē shuǐ.",
      "pinyin_numeric": "ta1 wei4 shen2 me0 bu4 xiang3 he1 ka1 fei1? yin1 wei4 ta1 kou3 ke3, xiang3 he1 shui3",
      "translation_en": "Why doesn't he want to drink coffee? Because he's thirsty and wants to drink water.",
      "translation_ko": "그는 왜 커피를 마시고 싶지 않나요? 목이 말라서 물을 마시고 싶어요."
    },
    {
      "text": "你為什麼想買這個？因為比較便宜。",
      "pinyin": "Nǐ wèishénme xiǎng mǎi zhège? Yīnwèi bǐjiào piányí.",
      "pinyin_numeric": "ni3 wei4 shen2 me0 xiang3 mai3 zhe4 ge0? yin1 wei4 bi3 jiao4 pian2 yi2",
      "translation_en": "Why do you want to buy this? Because it's cheaper.",
      "translation_ko": "왜 이것을 사고 싶으세요? 더 싸기 때문이에요."
    },
    {
      "text": "她為什麼不想去？因為她太累了。",
      "pinyin": "Tā wèishénme bù xiǎng qù? Yīnwèi tā tài lèi le.",
      "pinyin_numeric": "ta1 wei4 shen2 me0 bu4 xiang3 qu4? yin1 wei4 ta1 tai4 lei4 le0",
      "translation_en": "Why doesn't she want to go? Because she's too tired.",
      "translation_ko": "그녀는 왜 가고 싶지 않나요? 너무 피곤하기 때문이에요."
    },
    {
      "text": "我為什麼不想喝茶？因為我想省錢。",
      "pinyin": "Wǒ wèishénme bù xiǎng hē chá? Yīnwèi wǒ xiǎng shěng qián.",
      "pinyin_numeric": "wo3 wei4 shen2 me0 bu4 xiang3 he1 cha2? yin1 wei4 wo3 xiang3 sheng3 qian2",
      "translation_en": "Why don't I want to drink tea? Because I want to save money.",
      "translation_ko": "왜 차를 마시고 싶지 않나요? 돈을 아끼고 싶기 때문이에요."
    },
    {
      "text": "你為什麼想休息？因為我剛下班，太忙了。",
      "pinyin": "Nǐ wèishénme xiǎng xiūxí? Yīnwèi wǒ gāng xiàbān, tài máng le.",
      "pinyin_numeric": "ni3 wei4 shen2 me0 xiang3 xiu1 xi2? yin1 wei4 wo3 gang1 xia4 ban1, tai4 mang2 le0",
      "translation_en": "Why do you want to rest? Because I just got off work and was too busy.",
      "translation_ko": "왜 쉬고 싶으세요? 방금 퇴근했고 너무 바빴기 때문이에요."
    },
    {
      "text": "他為什麼不想吃早餐？因為他忘記帶錢。",
      "pinyin": "Tā wèishénme bù xiǎng chī zǎocān? Yīnwèi tā wàngjì dài qián.",
      "pinyin_numeric": "ta1 wei4 shen2 me0 bu4 xiang3 chi1 zao3 can1? yin1 wei4 ta1 wang4 ji4 dai4 qian2",
      "translation_en": "Why doesn't he want to eat breakfast? Because he forgot to bring money.",
      "translation_ko": "그는 왜 아침을 먹고 싶지 않나요? 돈을 가져오는 것을 잊었기 때문이에요."
    },
    {
      "text": "你為什麼想買水？因為我口渴，沒有時間喝茶。",
      "pinyin": "Nǐ wèishénme xiǎng mǎi shuǐ? Yīnwèi wǒ kǒukě, méiyǒu shíjiān hē chá.",
      "pinyin_numeric": "ni3 wei4 shen2 me0 xiang3 mai3 shui3? yin1 wei4 wo3 kou3 ke3, mei2 you3 shi2 jian1 he1 cha2",
      "translation_en": "Why do you want to buy water? Because I'm thirsty and don't have time to drink tea.",
      "translation_ko": "왜 물을 사고 싶으세요? 목이 마르고 차를 마실 시간이 없기 때문이에요."
    },
    {
      "text": "她為什麼不想去公園？因為下雨了。",
      "pinyin": "Tā wèishénme bù xiǎng qù gōngyuán? Yīnwèi xià yǔ le.",
      "pinyin_numeric": "ta1 wei4 shen2 me0 bu4 xiang3 qu4 gong1 yuan2? yin1 wei4 xia4 yu3 le0",
      "translation_en": "Why doesn't she want to go to the park? Because it's raining.",
      "translation_ko": "그녀는 왜 공원에 가고 싶지 않나요? 비가 오기 때문이에요."
    }
  ]
}
